// Aggregate events per variant
const variants = {};
for (const event of $input.all()) {
  const vid = event.json.variant_id;
  if (!vid) continue;
  if (!variants[vid]) variants[vid] = { leads: 0, sent: 0, opened: 0, clicked: 0, replies: 0, positive: 0, meetings: 0, unsubs: 0 };
  variants[vid].leads++;
  if (event.json.event_type === 'sent') variants[vid].sent++;
  if (event.json.event_type === 'opened') variants[vid].opened++;
  if (event.json.event_type === 'clicked') variants[vid].clicked++;
  if (event.json.event_type === 'replied') {
    variants[vid].replies++;
    if (['interested','needs_more_info','pricing_question'].includes(event.json.reply_type)) variants[vid].positive++;
    if (event.json.reply_type === 'interested') variants[vid].meetings++;
  }
  if (event.json.event_type === 'unsubscribed') variants[vid].unsubs++;
}

// Compute rates
const results = Object.entries(variants).map(([vid, v]) => ({
  variant_id: vid,
  leads_assigned: v.leads,
  emails_sent: v.sent,
  emails_opened: v.opened,
  replies_total: v.replies,
  positive_replies: v.positive,
  meetings_booked: v.meetings,
  reply_rate: v.sent > 0 ? v.replies / v.sent : 0,
  positive_reply_rate: v.sent > 0 ? v.positive / v.sent : 0,
  meeting_rate: v.sent > 0 ? v.meetings / v.sent : 0,
}));

return results.map(r => ({ json: r }));

// Simplified winner detection: if one variant has 2x+ the positive reply rate and >10 sends, flag it
const results = $input.all().map(r => r.json);
if (results.length < 2) return [{ json: { winner_found: false, reason: 'need 2+ variants' } }];

const best = results.reduce((a, b) => a.positive_reply_rate > b.positive_reply_rate ? a : b);
const worst = results.reduce((a, b) => a.positive_reply_rate < b.positive_reply_rate ? a : b);

if (best.emails_sent >= 10 && best.positive_reply_rate >= worst.positive_reply_rate * 1.5) {
  return [{ json: { winner_found: true, winner_variant_id: best.variant_id, reason: 'Significant lead detected', recommendation: 'Stop experiment and adopt variant ' + best.variant_id } }];
}

return [{ json: { winner_found: false, reason: 'Not enough data or no clear winner' } }];
